   310	llvm::Value*
   311	EmitIR::operator()(CallExpr* obj)
   312	{
   313	  auto& irb = *mCurIrb;
   314	
   315	  // Get the function - head might be wrapped in ImplicitCastExpr
   316	  Expr* head = obj->head;
   317	  while (auto cast = head->dcst<ImplicitCastExpr>()) {
   318	    head = cast->sub;
   319	  }
   320	
   321	  llvm::Value* callee = nullptr;
   322	  if (auto dre = head->dcst<DeclRefExpr>()) {
   323	    callee = self(dre);
   324	  } else {
   325	    callee = emitRValue(head);
   326	  }
   327	
   328	  auto func = llvm::dyn_cast<llvm::Function>(callee);
   329	  if (!func) {
   330	    // It's a function pointer
   331	    auto fty = llvm::dyn_cast<llvm::FunctionType>(
   332	      callee->getType()->getPointerElementType());
   333	    if (!fty) {
   334	      // Try to get function type from the head expression
   335	      auto headType = head->type;
   336	      if (auto ft = headType->texp->dcst<FunctionType>()) {
   337	        fty = llvm::dyn_cast<llvm::FunctionType>(self(headType));
   338	      }
   339	    }
   340	  }
   341	
   342	  std::vector<llvm::Value*> args;
   343	  auto fty = func ? func->getFunctionType() : nullptr;
   344	  for (size_t i = 0; i < obj->args.size(); ++i) {
   345	    auto arg = emitRValue(obj->args[i]);
   346	    if (fty && i < fty->getNumParams()) {
   347	      auto paramTy = fty->getParamType(i);
   348	      if (arg->getType() != paramTy) {
   349	        if (paramTy->isIntegerTy() && arg->getType()->isIntegerTy()) {
   350	          arg = irb.CreateIntCast(arg, paramTy, true);
   351	        }
   352	      }
   353	    }
   354	    args.push_back(arg);
   355	  }
   356	
   357	  if (func)
   358	    return irb.CreateCall(func, args);
   359	  else
   360	    return irb.CreateCall(fty, callee, args);
